"use client";

import { useState } from "react";
import { searchDrugs, syncDrugs } from "@/utils/drugApi";

export default function DrugPage() {
  const [keyword, setKeyword] = useState("");
  const [drugs, setDrugs] = useState<any[]>([]);
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState("");

  // ⭐️ 페이지네이션 상태 추가
  const [page, setPage] = useState(0); // 현재 페이지 (0부터 시작)
  const [totalPages, setTotalPages] = useState(0); // 전체 페이지 수

  // 🔍 데이터 불러오기 공통 함수
  const fetchDrugs = async (searchKeyword: string, searchPage: number) => {
    setLoading(true);
    setMessage("데이터를 불러오는 중...");
    try {
      // API 호출 (keyword, page, size=10)
      const data = await searchDrugs(searchKeyword, searchPage, 10);
      
      // 백엔드 Page 객체 구조 분해
      setDrugs(data.content);       // 실제 데이터 리스트
      setTotalPages(data.totalPages); // 전체 페이지 수
      setPage(data.number);         // 현재 페이지 번호 업데이트
      
      setMessage(`총 ${data.totalElements}개의 약품이 검색되었습니다.`);
    } catch (err) {
      setMessage("검색 중 오류가 발생했습니다.");
      setDrugs([]);
    } finally {
      setLoading(false);
    }
  };

  // 🔍 검색 버튼 클릭 시 (0페이지부터 시작)
  const handleSearch = (e: React.FormEvent) => {
    e.preventDefault();
    if (!keyword) return;
    setPage(0); // 검색 시 페이지 0으로 초기화
    fetchDrugs(keyword, 0);
  };

  // 📄 페이지 변경 핸들러 (이전/다음)
  const handlePageChange = (newPage: number) => {
    if (newPage >= 0 && newPage < totalPages) {
      fetchDrugs(keyword, newPage);
      // 화면 최상단으로 스크롤 이동 (선택사항)
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  };

  // 🔄 전체 동기화
  const handleSync = async () => {
    if (!confirm("모든 e약은요 데이터를 동기화하시겠습니까? (시간이 소요됩니다)")) return;

    setLoading(true);
    setMessage("데이터 동기화 중... 잠시만 기다려주세요.");
    try {
      const resultMsg = await syncDrugs();
      setMessage("✅ " + resultMsg);
    } catch (err) {
      setMessage("❌ 동기화 실패! 백엔드 로그를 확인해주세요.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="p-8 max-w-5xl mx-auto min-h-screen bg-gray-50">
      <h1 className="text-3xl font-bold mb-6 text-gray-800">💊 e약은요 관리자 페이지</h1>

      {/* 상단 컨트롤 패널 */}
      <div className="flex flex-col md:flex-row gap-4 mb-8 bg-white p-6 rounded-xl shadow-sm border">
        {/* 검색 폼 */}
        <form onSubmit={handleSearch} className="flex-1 flex gap-2">
          <input
            type="text"
            placeholder="약 이름 검색 (예: 타이레놀)"
            className="flex-1 p-3 border rounded-lg shadow-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
            value={keyword}
            onChange={(e) => setKeyword(e.target.value)}
          />
          <button
            type="submit"
            disabled={loading}
            className="bg-blue-600 text-white px-6 py-3 rounded-lg font-bold hover:bg-blue-700 transition disabled:bg-gray-400"
          >
            검색
          </button>
        </form>

        <button
          onClick={handleSync}
          disabled={loading}
          className="bg-green-600 text-white px-6 py-3 rounded-lg font-bold hover:bg-green-700 transition shadow-md disabled:bg-gray-400 whitespace-nowrap"
        >
          {loading ? "작업 중..." : "🔄 전체 동기화"}
        </button>
      </div>

      {/* 상태 메시지 */}
      {message && (
        <div className={`p-4 mb-6 rounded-lg text-center font-medium ${message.includes("❌") ? "bg-red-100 text-red-700" : "bg-blue-100 text-blue-700"}`}>
          {message}
        </div>
      )}

      {/* 로딩 스피너 */}
      {loading && (
        <div className="flex justify-center my-20">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600"></div>
        </div>
      )}

      {/* 결과 리스트 */}
      {!loading && drugs.length > 0 && (
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-8">
          {drugs.map((drug) => (
            <div key={drug.itemSeq} className="border rounded-xl p-5 shadow-sm hover:shadow-md transition bg-white flex flex-col h-full">
              <div className="flex justify-between items-start mb-3">
                <h3 className="text-lg font-bold text-gray-900 line-clamp-1">{drug.itemName}</h3>
                <span className="text-xs bg-gray-100 text-gray-500 px-2 py-1 rounded border">
                  No. {drug.itemSeq}
                </span>
              </div>
              
              <p className="text-sm text-blue-600 mb-3 font-medium">{drug.entpName}</p>
              
              {drug.itemImage && (
                <div className="w-full h-48 mb-3 bg-gray-100 rounded-lg overflow-hidden border">
                  <img src={drug.itemImage} alt={drug.itemName} className="w-full h-full object-cover" />
                </div>
              )}

              <div className="mt-auto bg-gray-50 p-3 rounded text-sm text-gray-600 h-24 overflow-hidden relative group">
                <strong className="block mb-1 text-gray-800">효능:</strong>
                <p className="line-clamp-3">{drug.efficacy}</p>
              </div>
            </div>
          ))}
        </div>
      )}

      {/* ⭐️ 페이지네이션 컨트롤 (데이터가 있을 때만 표시) */}
      {!loading && drugs.length > 0 && (
        <div className="flex justify-center items-center gap-4 py-8">
          <button
            onClick={() => handlePageChange(page - 1)}
            disabled={page === 0}
            className="px-4 py-2 border rounded-lg bg-white hover:bg-gray-50 disabled:bg-gray-100 disabled:text-gray-400 font-medium transition"
          >
            &lt; 이전
          </button>
          
          <span className="text-gray-700 font-medium">
             Page <span className="text-blue-600">{page + 1}</span> of {totalPages}
          </span>

          <button
            onClick={() => handlePageChange(page + 1)}
            disabled={page >= totalPages - 1}
            className="px-4 py-2 border rounded-lg bg-white hover:bg-gray-50 disabled:bg-gray-100 disabled:text-gray-400 font-medium transition"
          >
            다음 &gt;
          </button>
        </div>
      )}
      
      {!loading && drugs.length === 0 && !message.includes("동기화") && (
        <div className="text-center text-gray-400 py-20 bg-white rounded-xl border border-dashed">
          데이터가 없습니다. 검색어를 입력해주세요.
        </div>
      )}
    </div>
  );
}